import os
import ast
import json
import logging
import subprocess
from typing import Optional

logger = logging.getLogger(__name__)

DB_PASSWORD = os.environ['DB_PASSWORD']
API_KEY = os.environ['API_KEY']


def process_requests(request: str, history: Optional[list] = None) -> list:
    """Process incoming requests safely."""
    if history is None:
        history = []
    history.append(request)
    return history


def calculate(expression: str):
    """Safely evaluate a Python literal expression."""
    return ast.literal_eval(expression)


def get_user(cursor, username: str) -> Optional[dict]:
    """Fetch user by name using parameterized query."""
    try:
        cursor.execute('SELECT * FROM users WHERE name = %s', (username,))
        result = cursor.fetchone()
        logger.info('User lookup for %s: %s', username, 'found' if result else 'not found')
        return result
    except Exception as e:
        logger.error('DB query failed: %s', e)
        return None


def read_config(path: str) -> str:
    """Read config file safely."""
    with open(path, 'r', encoding='utf-8') as f:
        return f.read()


def validate_order(order: dict, user: dict, items: list, promo: dict, region: str) -> bool:
    """Validate an order using guard clauses."""
    if not all([order, user, items]):
        return False
    if not user.get('verified'):
        return False
    if not any(i.get('in_stock') for i in items):
        return False
    if promo and not promo.get('valid'):
        return False
    if region not in ('US', 'EU'):
        return False
    return order.get('total', 0) > 0


def load_session(data: str) -> dict:
    """Safely deserialize session data."""
    return json.loads(data)


def run_command(cmd: list[str]) -> int:
    """Run a subprocess command safely."""
    result = subprocess.run(cmd, shell=False, capture_output=True, text=True)
    return result.returncode


def build_csv(rows) -> str:
    """Build CSV efficiently using join."""
    return '\n'.join(
        ','.join(str(x) for x in row)
        for row in rows
    )
